import React, { useState, useEffect } from "react";
import ReactMapGL, { Marker, Popup } from "react-map-gl";
import 'mapbox-gl/dist/mapbox-gl.css';

function WorldMap() {
  const [viewport, setViewport] = useState({
    latitude: 20,
    longitude: 0,
    zoom: 1.5,
    width: "100%",
    height: "100vh"
  });

  const [hotspots, setHotspots] = useState([]);
  const [selectedSpot, setSelectedSpot] = useState(null);

  useEffect(() => {
    fetch("http://localhost:5000/api/news")
      .then(res => res.json())
      .then(data => {
        if (data.hotspots) {
          setHotspots(data.hotspots);
        } else {
          setHotspots([]);
        }
      })
      .catch(err => {
        console.error(err);
        setHotspots([]);
      });
  }, []);

  const handleComingSoon = (feature) => {
    alert(`${feature} feature coming soon!`);
  };

  return (
    <div style={{ fontFamily: "Inter, Segoe UI, Roboto, sans-serif", height: "100vh", display: "flex", flexDirection: "column", backgroundColor: "#0d0d0d", color: "#fff" }}>
      
      {/* Top Navigation Bar */}
      <div style={{
        height: "60px",
        backgroundColor: "#111",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 20px",
        boxShadow: "0 2px 6px rgba(0,0,0,0.6)"
      }}>
        <h1 style={{ fontSize: "20px", margin: 0, color: "#fff" }}>🌐 Geopolitical Dashboard</h1>
        <div>
          <button onClick={() => handleComingSoon("Analytics")} style={navButtonStyle}>Analytics</button>
          <button onClick={() => handleComingSoon("Filters")} style={navButtonStyle}>Filters</button>
          <button onClick={() => handleComingSoon("Reports")} style={navButtonStyle}>Reports</button>
          <button onClick={() => handleComingSoon("Settings")} style={navButtonStyle}>Settings</button>
        </div>
      </div>

      {/* Moving Headlines Ticker */}
      <div style={{
        height: "40px",
        backgroundColor: "#1a1a1a",
        overflow: "hidden",
        display: "flex",
        alignItems: "center",
        borderBottom: "1px solid #333"
      }}>
        <div style={{
          display: "inline-block",
          whiteSpace: "nowrap",
          animation: "ticker 30s linear infinite"
        }}>
          {hotspots.map((spot, i) => (
            <span key={i} style={{ marginRight: "50px", color: "#0077cc", cursor: "pointer" }}
              onClick={() => window.open(spot.url, "_blank")}
            >
              🔴 {spot.title}
            </span>
          ))}
        </div>
      </div>

      {/* Map */}
      <div style={{ flex: 1 }}>
        <ReactMapGL
          {...viewport}
          mapStyle="mapbox://styles/mapbox/streets-v12"
          mapboxApiAccessToken={process.env.REACT_APP_MAPBOX_TOKEN}
          onViewportChange={setViewport}
        >
          {hotspots.map((spot, i) => (
            <Marker key={i} latitude={spot.lat} longitude={spot.lng}>
              <div
                onClick={() => setSelectedSpot(spot)}
                style={{
                  cursor: "pointer",
                  backgroundColor: "#e63946",
                  borderRadius: "50%",
                  width: "18px",
                  height: "18px",
                  border: "2px solid #fff",
                  boxShadow: "0 0 10px rgba(230,57,70,0.8)",
                  transition: "transform 0.2s ease"
                }}
                onMouseEnter={e => e.currentTarget.style.transform = "scale(1.3)"}
                onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}
              />
            </Marker>
          ))}

          {selectedSpot && (
            <Popup
              latitude={selectedSpot.lat}
              longitude={selectedSpot.lng}
              onClose={() => setSelectedSpot(null)}
              closeOnClick={false}
              anchor="top"
            >
              <div style={{
                maxWidth: "260px",
                padding: "12px",
                borderRadius: "8px",
                backgroundColor: "#111",
                color: "#fff",
                boxShadow: "0 4px 12px rgba(0,0,0,0.6)",
                animation: "fadeIn 0.3s ease"
              }}>
                <strong style={{ color: "#0077cc" }}>{selectedSpot.title}</strong>
                <br />
                <small style={{ color: "#aaa" }}>{selectedSpot.source}</small>
                <br />
                <a href={selectedSpot.url} target="_blank" rel="noopener noreferrer" style={{ color: "#e63946" }}>
                  Read more →
                </a>
              </div>
            </Popup>
          )}
        </ReactMapGL>
      </div>

      {/* CSS animation */}
      <style>
        {`
          @keyframes ticker {
            0% { transform: translateX(100%); }
            100% { transform: translateX(-100%); }
          }
        `}
      </style>
    </div>
  );
}

const navButtonStyle = {
  backgroundColor: "#222",
  color: "#fff",
  border: "none",
  padding: "8px 12px",
  marginLeft: "10px",
  borderRadius: "4px",
  cursor: "pointer",
  fontSize: "14px",
  transition: "background-color 0.2s ease"
};

export default WorldMap;
